// ❌ BAD - public delegate field lets anyone invoke or clear all subscribers
public OrderShippedHandler? OrderShipped;
// caller can do: service.OrderShipped = null; // wipes all subscribers

// ✅ GOOD - event keyword restricts callers to += and -= only
public class OrderService
{
    public event EventHandler<int>? OrderShipped;

    public void Ship(int orderId)
    {
        // process shipment...
        OrderShipped?.Invoke(this, orderId);
    }
}

var svc = new OrderService();
svc.OrderShipped += (_, id) => Console.WriteLine($"Order {id} shipped");
svc.Ship(42);

// ❌ BAD - using object loses type safety and causes boxing for value types
public class OldRepository
{
    public object GetById(int id) => _db.Find(id);
}
var order = (Order)repo.GetById(1); // runtime cast, can fail

// ✅ GOOD - generic with constraint, type-safe, no casting
public class Repository<T> where T : class, IEntity
{
    private readonly AppDbContext _db;
    public Repository(AppDbContext db) => _db = db;
    public Task<T?> GetByIdAsync(int id) => _db.Set<T>().FindAsync(id).AsTask();
}

// ❌ BAD - ToList() before Where loads the entire Orders table into memory
var topCustomers = db.Orders.ToList()
    .Where(o => o.Status == OrderStatus.Shipped)
    .GroupBy(o => o.CustomerId);

// ✅ GOOD - Where stays on IQueryable so EF translates it all to one SQL query
var topCustomers = db.Orders
    .Where(o => o.Status == OrderStatus.Shipped)
    .GroupBy(o => o.CustomerId)
    .Select(g => new { CustomerId = g.Key, Total = g.Sum(o => o.Amount) })
    .OrderByDescending(x => x.Total)
    .Take(10)
    .ToList();

// ❌ BAD - verbose if/else with manual casting, easy to miss cases
string Describe(PaymentMethod method)
{
    if (method is CreditCard) { var c = (CreditCard)method; return "Card: " + c.Last4; }
    else if (method is BankTransfer) return "Bank";
    else return "Unknown";
}

// ✅ GOOD - switch expression with type and property patterns
string Describe(PaymentMethod method) => method switch
{
    CreditCard { Last4: var digits } => $"Card ending {digits}",
    BankTransfer { Amount: > 10000m } bt => $"Large transfer: {bt.Reference}",
    BankTransfer => "Bank transfer",
    null => "No payment",
    _ => "Unknown method"
};

// ❌ BAD - static utility class with awkward call syntax
public static class OrderHelper
{
    public static bool IsOverdue(Order order) => order.DueDate < DateTime.UtcNow;
}
bool late = OrderHelper.IsOverdue(order); // not fluent

// ✅ GOOD - extension method reads like natural language
public static class OrderExtensions
{
    public static bool IsOverdue(this Order order)
        => order.DueDate < DateTime.UtcNow;

    public static bool IsHighValue(this Order order)
        => order.Total > 10_000m;
}
bool result = order.IsOverdue() && order.IsHighValue();

// ❌ BAD - builds the entire list in memory before returning anything
public List<InvoiceRow> ReadInvoiceRows(string filePath)
{
    var rows = new List<InvoiceRow>();
    foreach (var line in File.ReadAllLines(filePath))
        rows.Add(Parse(line));
    return rows; // 500 MB CSV = 500 MB in memory at once
}

// ✅ GOOD - streams one row at a time, caller controls how many to read
public IEnumerable<InvoiceRow> ReadInvoiceRows(string filePath)
{
    foreach (var line in File.ReadLines(filePath))
        yield return Parse(line);
}

// ❌ BAD - class with manual equality is verbose and error-prone
public class ProductDto
{
    public int Id { get; init; }
    public string Name { get; init; } = "";
    // must manually override Equals and GetHashCode
}

// ✅ GOOD - record generates everything automatically
public record ProductDto(int Id, string Name, decimal Price);

var original = new ProductDto(1, "Laptop", 999m);
var discounted = original with { Price = 799m }; // new record
Console.WriteLine(original == discounted);            // false
Console.WriteLine(original == new ProductDto(1, "Laptop", 999m)); // true

// ❌ BAD - System.Tuple is a class, no names, awkward Item1/Item2 access
public Tuple<string, decimal> GetInvoiceSummary(int invoiceId)
    => Tuple.Create("INV-001", 1500m);
var result = GetInvoiceSummary(1);
Console.WriteLine(result.Item2); // what is Item2? unclear

// ✅ GOOD - ValueTuple with names and deconstruction
public (string Reference, decimal Total) GetInvoiceSummary(int invoiceId)
    => ("INV-001", 1500m);

var (reference, total) = GetInvoiceSummary(1);
Console.WriteLine($"{reference}: {total:C}");
